    fn tokenToSymbol(self: *Parser, token: Token) u16 {
        return switch (token.cat) {
            .eof => 1,
            .ident => self.identToSymbol(token),
            .comment => 53,
            .newline => 55,
            .flag => 74,
            .integer => 76,
            .string_sq => 83,
            .string_dq => 84,
            .real => 85,
            .variable => 86,
            .var_braced => 87,
            .regex => 88,
            .dollar_paren => 91,
            .redir_fd_dup => 99,
            .redir_fd_out => 100,
            .redir_fd_in => 101,
            .heredoc_sq => 103,
            .heredoc_body => 104,
            .heredoc_dq => 106,
            .heredoc_bt => 107,
            .heredoc_end => 108,
            .indent => 129,
            .outdent => 132,
            .missing => 135,
            .lparen_tight => 136,
            .list_start => 148,
            .assign => 56,
            .minus => 58,
            .semi => 60,
            .bg => 61,
            .pipe => 68,
            .not_sym => 69,
            .lparen => 71,
            .rparen => 72,
            .redir_out => 92,
            .redir_in => 94,
            .lbrace => 125,
            .rbrace => 128,
            .comma => 137,
            .plus => 143,
            .star => 144,
            .slash => 145,
            .percent => 146,
            .rbracket => 150,
            .plus_assign => 59,
            .and_sym => 62,
            .or_sym => 64,
            .pipe_err => 67,
            .proc_sub_in => 89,
            .proc_sub_out => 90,
            .redir_append => 93,
            .redir_err => 95,
            .redir_err_app => 96,
            .redir_both => 97,
            .redir_dup => 98,
            .herestring => 102,
            .eq => 112,
            .ne => 113,
            .le => 114,
            .ge => 115,
            .match => 116,
            .nomatch => 117,
            .default_op => 142,
            .power => 147,
            else => 2, // error
        };
    }

    fn identToSymbol(self: *Parser, token: Token) u16 {
        const text = self.source[token.pos..][0..token.len];
        if (text.len == 0) return SYM_IDENT;
        if (self.try_ident_as_if(token, text)) |sym| return sym;
        if (self.try_ident_as_unless(token, text)) |sym| return sym;
        if (self.try_ident_as_else(token, text)) |sym| return sym;
        if (self.try_ident_as_for(token, text)) |sym| return sym;
        if (self.try_ident_as_in(token, text)) |sym| return sym;
        if (self.try_ident_as_while(token, text)) |sym| return sym;
        if (self.try_ident_as_until(token, text)) |sym| return sym;
        if (self.try_ident_as_try(token, text)) |sym| return sym;
        if (self.try_ident_as_and(token, text)) |sym| return sym;
        if (self.try_ident_as_or(token, text)) |sym| return sym;
        if (self.try_ident_as_not(token, text)) |sym| return sym;
        if (self.try_ident_as_xor(token, text)) |sym| return sym;
        if (self.try_ident_as_cmd(token, text)) |sym| return sym;
        if (self.try_ident_as_key(token, text)) |sym| return sym;
        if (self.try_ident_as_set(token, text)) |sym| return sym;
        if (self.try_ident_as_test(token, text)) |sym| return sym;
        if (self.try_ident_as_source(token, text)) |sym| return sym;
        if (self.try_ident_as_exit(token, text)) |sym| return sym;
        if (self.try_ident_as_break(token, text)) |sym| return sym;
        if (self.try_ident_as_continue(token, text)) |sym| return sym;
        if (self.try_ident_as_exec(token, text)) |sym| return sym;
        return SYM_IDENT;
    }

    fn try_ident_as_if(self: *Parser, token: Token, text: []const u8) ?u16 {
        _ = token;
        const state = self.state_stack.getLast();
        if (if_as(text)) |id| {
            const sym = if_to_symbol[@intFromEnum(id)];
            if (sym != 0 and getAction(state, sym) != 0) {
                self.last_matched_id = @intFromEnum(id);
                return sym;
            }
        }
        return null;
    }

